document.addEventListener("DOMContentLoaded",function(){const slider=document.querySelector(".cert-slider");if(!slider)return;const track=slider.querySelector(".cert-track"),slides=Array.from(slider.querySelectorAll(".cert-slide")),dotsWrap=slider.querySelector(".cert-dots"),total=slides.length;let current=0,isMoving=false;slides.forEach(function(slide){track.appendChild(slide.cloneNode(true))});dotsWrap.innerHTML="";for(let i=0;i<total;i++){const dot=document.createElement("span");dot.className="cert-dot"+(i===0?" active":"");dot.addEventListener("click",function(){if(isMoving||i===current)return;current=i;moveTo(current)});dotsWrap.appendChild(dot)}const dots=slider.querySelectorAll(".cert-dot");function updateDots(){dots.forEach(function(dot){dot.classList.remove("active")});dots[current%total].classList.add("active")}function moveTo(index){isMoving=true;track.style.transform="translateX("+(-index*20)+"%)";updateDots();setTimeout(function(){isMoving=false},650)}setInterval(function(){if(isMoving)return;current++;if(current>=total){moveTo(current);setTimeout(function(){track.style.transition="none";current=0;track.style.transform="translateX(0)";updateDots();setTimeout(function(){track.style.transition="transform 0.65s cubic-bezier(.22,.61,.36,1)"},50)},650)}else{moveTo(current)}},3000);const lightbox=document.querySelector(".cert-lightbox"),lightboxImg=lightbox.querySelector("img"),closeBtn=lightbox.querySelector(".cert-lightbox-close");document.addEventListener("click",function(e){if(e.target.closest(".cert-slide img")){lightboxImg.src=e.target.src;lightbox.classList.add("active")}if(e.target.classList.contains("cert-lightbox")||e.target.classList.contains("cert-lightbox-close")){lightbox.classList.remove("active");lightboxImg.src=""}})});